// ── HTML Table → Markdown ─────────────────────────────────────
function htmlTableToMd(html: string): string {
  try {
    const doc = new DOMParser().parseFromString(html, 'text/html')
    const table = doc.querySelector('table')
    if (!table) return ''
    const rows = Array.from(table.querySelectorAll('tr'))
    if (!rows.length) return ''
    const toRow = (cells: Element[]) =>
      '| ' + cells.map(c => (c.textContent ?? '').trim().replace(/\|/g, '\\|')).join(' | ') + ' |'
    const headerCells = Array.from(rows[0].querySelectorAll('th,td'))
    const lines = [
      toRow(headerCells),
      '| ' + headerCells.map(() => '---').join(' | ') + ' |',
    ]
    for (let i = 1; i < rows.length; i++)
      lines.push(toRow(Array.from(rows[i].querySelectorAll('td,th'))))
    return lines.join('\n')
  } catch { return '' }
}

// ── Markdown → Editor HTML ─────────────────────────────────────
function mdToEditorHtml(md: string): string {
  if (!md.trim()) return ''
  const esc = (s: string) => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  const inline = (s: string): string => {
    let h = esc(s)
    // {#hex:text} 또는 {colorname:text} → 에디터 색상 span
    h = h.replace(/\{([^}:]+):([^}]*)\}/g, (match, key, text) => {
      const val = key.startsWith('#') ? key : null
      return val ? `<span style="color:${val}" data-color="${val}">${text}</span>` : match
    })
    h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    h = h.replace(/\*(.+?)\*/g, '<em>$1</em>')
    h = h.replace(/`(.+?)`/g, '<code>$1</code>')
    return h
  }
  return md.split('\n').map(line => {
    if (/^# /.test(line))  return `<h1>${inline(line.slice(2))}</h1>`
    if (/^## /.test(line)) return `<h2>${inline(line.slice(3))}</h2>`
    if (/^- /.test(line))  return `<li>${inline(line.slice(2))}</li>`
    return `<p>${inline(line) || '<br>'}</p>`
  }).join('')
}

// ── Editor DOM → Markdown ──────────────────────────────────────
function domToMd(root: HTMLElement): string {
  function inlineMd(node: Node): string {
    if (node.nodeType === Node.TEXT_NODE)
      return (node.textContent ?? '').replace(/\u200B/g, '')
    if (!(node instanceof HTMLElement)) return ''
    const inner = Array.from(node.childNodes).map(inlineMd).join('')
    switch (node.tagName.toLowerCase()) {
      case 'strong': case 'b': return `**${inner}**`
      case 'em':     case 'i': return `*${inner}*`
      case 'code':             return `\`${inner}\``
      case 'br':               return ''
      case 'span': {
        const c = node.getAttribute('data-color')
        // Markdown.tsx 형식: {#hex:텍스트}
        return c ? `{${c}:${inner}}` : inner
      }
      default: return inner
    }
  }
  const lines: string[] = []
  for (const child of Array.from(root.childNodes)) {
    if (child.nodeType === Node.TEXT_NODE) {
      const t = (child.textContent ?? '').replace(/\u200B/g, '')
      if (t.trim()) lines.push(t)
      continue
    }
    if (!(child instanceof HTMLElement)) continue
    const tag = child.tagName.toLowerCase()
    if (tag === 'ul' || tag === 'ol') {
      for (const li of Array.from(child.children)) lines.push(`- ${inlineMd(li)}`)
    } else if (tag === 'li') {
      lines.push(`- ${inlineMd(child)}`)
    } else if (tag === 'h1') {
      lines.push(`# ${inlineMd(child)}`)
    } else if (tag === 'h2') {
      lines.push(`## ${inlineMd(child)}`)
    } else if (tag === 'p' || tag === 'div') {
      const t = inlineMd(child)
      lines.push(t)
    } else {
      const t = inlineMd(child)
      if (t) lines.push(t)
    }
  }
  return lines.join('\n')
}

// ── 색상 팔레트 ────────────────────────────────────────────────
const MD_PALETTE = ['#f87171','#fb923c','#fbbf24','#4ade80','#60a5fa','#a78bfa','#f472b6']

// ── MarkdownEditor ─────────────────────────────────────────────
interface MarkdownEditorProps {
  value: string
  onChange: (v: string) => void
  onCtrlEnter?: () => void
  placeholder?: string
  style?: React.CSSProperties
  className?: string
  editorRef?: React.RefObject<HTMLDivElement>
}

function MarkdownEditor({ value, onChange, onCtrlEnter, placeholder, style, className, editorRef }: MarkdownEditorProps) {
  const inner = useRef<HTMLDivElement>(null)
  const ref   = (editorRef ?? inner) as React.RefObject<HTMLDivElement>
  const lastMd   = useRef('')
  const composing = useRef(false)
  const [hovColor, setHovColor] = useState<string | null>(null)

  // 외부 value 변경 시 DOM 재초기화 (직접 타이핑한 변경은 스킵)
  useEffect(() => {
    const el = ref.current
    if (!el || lastMd.current === value) return
    lastMd.current = value
    el.innerHTML = mdToEditorHtml(value)
  }, [value]) // eslint-disable-line

  const emit = () => {
    const el = ref.current
    if (!el) return
    const md = domToMd(el)
    lastMd.current = md
    onChange(md)
  }

  const getCaretBlock = (): HTMLElement | null => {
    const sel = window.getSelection()
    if (!sel?.rangeCount) return null
    let node: Node | null = sel.getRangeAt(0).startContainer
    while (node && node !== ref.current) {
      if (node instanceof HTMLElement && /^(P|H[1-6]|LI|DIV)$/.test(node.tagName)) return node
      node = node.parentNode
    }
    return null
  }

  const transformBlock = (block: HTMLElement, tag: string) => {
    const el = document.createElement(tag)
    el.innerHTML = '<br>'
    block.replaceWith(el)
    const r = document.createRange()
    r.setStart(el, 0); r.collapse(true)
    const sel = window.getSelection()!
    sel.removeAllRanges(); sel.addRange(r)
    emit()
  }

  // 커서 직전 텍스트가 **..** *..* `..` 패턴으로 끝나면 inline 요소로 변환
  const tryInlineTransform = (): boolean => {
    const sel = window.getSelection()
    if (!sel?.rangeCount) return false
    const range = sel.getRangeAt(0)
    if (!range.collapsed || range.startContainer.nodeType !== Node.TEXT_NODE) return false
    const textNode = range.startContainer as Text
    const before = textNode.textContent!.slice(0, range.startOffset)
    const after  = textNode.textContent!.slice(range.startOffset)

    const patterns: [RegExp, string][] = [
      [/^(.*)\*\*([^*\n]+)\*\*$/, 'strong'],
      [/^(.*[^*]|^)\*([^*\n]+)\*$/, 'em'],
      [/^(.*)`([^`\n]+)`$/, 'code'],
    ]
    for (const [re, tag] of patterns) {
      const m = before.match(re)
      if (!m) continue
      const frag = document.createDocumentFragment()
      if (m[1]) frag.appendChild(document.createTextNode(m[1]))
      const el = document.createElement(tag)
      el.textContent = m[2]
      frag.appendChild(el)
      const cursorNode = document.createTextNode('\u200B')
      frag.appendChild(cursorNode)
      if (after) frag.appendChild(document.createTextNode(after))
      textNode.parentNode!.replaceChild(frag, textNode)
      const r = document.createRange()
      r.setStart(cursorNode, 1); r.collapse(true)
      sel.removeAllRanges(); sel.addRange(r)
      return true
    }
    return false
  }

  // 선택 텍스트에 색상 적용
  const applyColor = (color: string) => {
    const sel = window.getSelection()
    if (!sel?.rangeCount) return
    const range = sel.getRangeAt(0)
    if (range.collapsed) return
    const span = document.createElement('span')
    span.setAttribute('data-color', color)
    span.style.color = color
    const fragment = range.extractContents()
    // 기존 color span 제거
    fragment.querySelectorAll('[data-color]').forEach(el => el.replaceWith(...Array.from(el.childNodes)))
    span.appendChild(fragment)
    range.insertNode(span)
    // 삽입된 span 선택 유지
    const newRange = document.createRange()
    newRange.selectNodeContents(span)
    sel.removeAllRanges(); sel.addRange(newRange)
    emit()
    ref.current?.focus()
  }

  // 선택 텍스트 색상 제거
  const clearColor = () => {
    const sel = window.getSelection()
    if (!sel?.rangeCount) return
    const range = sel.getRangeAt(0)
    const root = ref.current!
    // 커서가 color span 안에 있으면 그 span 해제
    if (range.collapsed) {
      let node: Node | null = range.startContainer
      while (node && node !== root) {
        if (node instanceof HTMLElement && node.hasAttribute('data-color')) {
          node.replaceWith(...Array.from(node.childNodes))
          emit(); return
        }
        node = node.parentNode
      }
      return
    }
    // 선택 범위 내 color span 모두 해제
    const fragment = range.extractContents()
    fragment.querySelectorAll('[data-color]').forEach(el => el.replaceWith(...Array.from(el.childNodes)))
    range.insertNode(fragment)
    emit()
    ref.current?.focus()
  }

  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
      e.preventDefault(); onCtrlEnter?.(); return
    }
    if (composing.current) return

    if (e.key === ' ') {
      const block = getCaretBlock()
      const text = (block?.textContent ?? '').replace(/\u200B/g, '').trim()
      if (text === '#')  { e.preventDefault(); transformBlock(block!, 'h1'); return }
      if (text === '##') { e.preventDefault(); transformBlock(block!, 'h2'); return }
      if (text === '-')  { e.preventDefault(); transformBlock(block!, 'li'); return }
      if (tryInlineTransform()) { e.preventDefault(); emit(); return }
    }

    // 빈 li에서 Enter → p로 변환
    if (e.key === 'Enter' && !e.shiftKey) {
      const block = getCaretBlock()
      if (block?.tagName.toLowerCase() === 'li' &&
          !block.textContent?.replace(/\u200B/g, '').trim()) {
        e.preventDefault(); transformBlock(block, 'p')
      }
    }
  }

  const handlePaste = (e: React.ClipboardEvent<HTMLDivElement>) => {
    const html = e.clipboardData.getData('text/html')
    if (html?.includes('<table')) {
      e.preventDefault()
      const md = htmlTableToMd(html)
      if (md) document.execCommand('insertText', false, md)
      emit(); return
    }
    const text = e.clipboardData.getData('text/plain')
    if (text) {
      e.preventDefault()
      document.execCommand('insertText', false, text)
      emit()
    }
  }

  // style에서 레이아웃 관련 속성 분리 → 외부 래퍼에 적용
  const { overflowY, cursor, paddingBottom, lineHeight, padding: _padding, ...wrapperStyle } = style ?? {}

  return (
    <div style={{ display: 'flex', flexDirection: 'column', ...wrapperStyle }}>
      {/* ── 색상 팔레트 ── */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 5,
        padding: '5px 8px 4px',
        borderBottom: '1px solid rgba(255,255,255,.08)',
        flexShrink: 0,
      }}>
        {MD_PALETTE.map(c => (
          <button
            key={c}
            title={c}
            onMouseDown={(e) => { e.preventDefault(); applyColor(c) }}
            onMouseEnter={() => setHovColor(c)}
            onMouseLeave={() => setHovColor(null)}
            style={{
              width: hovColor === c ? 14 : 11,
              height: hovColor === c ? 14 : 11,
              borderRadius: '50%',
              background: c,
              border: 'none',
              cursor: 'pointer',
              padding: 0,
              flexShrink: 0,
              transition: 'width .12s, height .12s',
            }}
          />
        ))}
        {/* 색상 제거 */}
        <button
          title="색상 제거"
          onMouseDown={(e) => { e.preventDefault(); clearColor() }}
          onMouseEnter={() => setHovColor('clear')}
          onMouseLeave={() => setHovColor(null)}
          style={{
            width: 14, height: 14,
            borderRadius: '50%',
            background: 'transparent',
            border: `1px solid ${hovColor === 'clear' ? 'rgba(255,255,255,.5)' : 'rgba(255,255,255,.2)'}`,
            color: hovColor === 'clear' ? 'rgba(255,255,255,.7)' : 'rgba(255,255,255,.3)',
            cursor: 'pointer',
            padding: 0,
            fontSize: 9,
            lineHeight: 1,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            flexShrink: 0,
            transition: 'border-color .12s, color .12s',
          }}
        >
          ✕
        </button>
      </div>

      {/* ── 에디터 ── */}
      <div
        ref={ref}
        contentEditable
        suppressContentEditableWarning
        className={className}
        onInput={() => { if (!composing.current) emit() }}
        onKeyDown={handleKeyDown}
        onPaste={handlePaste}
        onCompositionStart={() => { composing.current = true }}
        onCompositionEnd={() => { composing.current = false; emit() }}
        data-placeholder={placeholder}
        style={{
          flex: 1,
          padding: '8px 10px',
          paddingBottom,
          overflowY,
          cursor,
          lineHeight,
          outline: 'none',
          wordBreak: 'break-word',
        }}
      />
    </div>
  )
}

// ── 아바타 색상 ────────────────────────────────────────────
function getAvatarColor(name: string): string {
  const palette = ['#D97757', '#B85E3F', '#E8956D', '#C75B39', '#A0522D', '#CF7A5A', '#E8A87C', '#8B4513']
  let h = 0
  for (const ch of name) h = (h * 31 + ch.charCodeAt(0)) & 0xff
  return palette[h % palette.length]
}

// ── 댓글 아이템 (메신저 스타일) ────────────────────────────
interface CommentItemProps {
  comment: Comment
  canEdit: boolean
  onUpdate: (text: string) => void
  onDelete: () => void
}

function CommentItem({ comment, canEdit, onUpdate, onDelete }: CommentItemProps) {
  const [editing, setEditing] = useState(false)
  const [draft, setDraft] = useState(comment.text)
  const [hov, setHov] = useState(false)

  const commit = () => {
    const t = draft.trim()
    if (t && t !== comment.text) onUpdate(t)
    else setDraft(comment.text)
    setEditing(false)
  }

  const labelColor = getAvatarColor(comment.author)

  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        padding: '6px 4px',
        borderRadius: 6,
        background: hov ? 'rgba(255,255,255,.03)' : 'transparent',
      }}
    >
      {/* 이름 레이블 + 시간 + 호버 액션 */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
        <span style={{
          display: 'inline-flex',
          alignItems: 'center',
          padding: '2px 8px',
          borderRadius: 2,
          fontSize: 10,
          fontWeight: 700,
          background: `${labelColor}22`,
          color: labelColor,
          border: `1px solid ${labelColor}44`,
          whiteSpace: 'nowrap',
        }}>
          {comment.author}
        </span>
        <span style={{ fontSize: 9, color: DARK.txL }}>{fmtTime(comment.createdAt)}</span>
        {comment.updatedAt && <span style={{ fontSize: 9, color: DARK.txL }}>(수정됨)</span>}
        {canEdit && !editing && hov && (
          <div style={{ display: 'flex', gap: 3, marginLeft: 'auto' }}>
            <button
              onClick={() => { setDraft(comment.text); setEditing(true) }}
              style={{ padding: '0 4px', height: 16, border: `1px solid ${DARK.brd}`, borderRadius: 3, background: 'transparent', color: DARK.txS, cursor: 'pointer', display: 'inline-flex', alignItems: 'center' }}
            >
              <svg width="10" height="10" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M11.06 2.06a1.5 1.5 0 0 1 2.12 0l.76.76a1.5 1.5 0 0 1 0 2.12L5.5 13.5 2 14l.5-3.5 8.56-8.44z" fill="currentColor" fillOpacity=".85"/>
              </svg>
            </button>
            <button
              onClick={() => { if (window.confirm('이 댓글을 삭제할까요?')) onDelete() }}
              style={{ fontSize: 10, padding: '0 5px', height: 16, border: `1px solid ${DARK.brd}`, borderRadius: 3, background: 'transparent', color: '#f87171', cursor: 'pointer', lineHeight: 1 }}
            >×</button>
          </div>
        )}
      </div>

      {/* 메시지 or 편집 */}
      {editing ? (
        <>
          <textarea
            autoFocus
            className="sb-scroll"
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            rows={2}
            style={{ width: '100%', padding: '6px 8px', border: `1px solid ${C.pri}`, borderRadius: 6, fontSize: 12, outline: 'none', fontFamily: 'inherit', resize: 'vertical', lineHeight: 1.5, boxSizing: 'border-box', background: DARK.bg3, color: DARK.txt }}
            onKeyDown={(e) => {
              if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') commit()
              if (e.key === 'Escape') { setDraft(comment.text); setEditing(false) }
            }}
          />
          <div style={{ display: 'flex', gap: 4, marginTop: 4 }}>
            <button onClick={() => { setDraft(comment.text); setEditing(false) }} style={{ fontSize: 10, padding: '3px 8px', border: `1px solid ${DARK.brd}`, borderRadius: 4, background: 'transparent', color: DARK.txS, cursor: 'pointer' }}>취소</button>
            <button onClick={commit} style={{ fontSize: 10, padding: '3px 10px', border: 'none', borderRadius: 2, background: C.pri, color: '#fff', cursor: 'pointer', fontWeight: 600 }}>저장</button>
          </div>
        </>
      ) : (
        <div style={{ fontSize: 12, color: DARK.txt, lineHeight: 1.6, whiteSpace: 'pre-wrap', wordBreak: 'break-word', padding: '2px 4px 0 4px' }}>
          {comment.text}
        </div>
      )}
    </div>
  )
}
