import { SDK_VERSION } from './version'
import type {
  AnnotSession,
  Comment,
  CreateLabelInput,
  CreatePinInput,
  LabelDef,
  PagePins,
  Pin,
  StorageAdapter,
} from './types'

export interface HttpAdapterOptions {
  /** 예: 'https://sb-api.aiatti.com' (후행 슬래시 없이) */
  baseUrl: string
  /** API 키 — Admin 에서 발급한 프로젝트 전용 토큰 (`sk_xxx`). 필수 */
  apiKey: string
  /** fetch 옵션 overrides (credentials, headers 등) */
  fetchInit?: (path: string) => RequestInit
  /** 요청 실패 시 호출 (기본: console.error) */
  onError?: (error: Error, context: { method: string; path: string }) => void
}

export function httpAdapter(options: HttpAdapterOptions): StorageAdapter {
  const base = options.baseUrl.replace(/\/+$/, '')
  const apiKey = options.apiKey
  if (!apiKey) {
    throw new Error('[specbridge] httpAdapter: apiKey is required')
  }
  const onError = options.onError ?? ((e, ctx) => console.error('[specbridge:http]', ctx, e))

  async function request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = `${base}${path}`
    const init: RequestInit = {
      method,
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
        Authorization: `Bearer ${apiKey}`,
        'X-SpecBridge-SDK-Version': SDK_VERSION,
      },
      body: body === undefined ? undefined : JSON.stringify(body),
      ...(options.fetchInit?.(path) ?? {}),
    }
    const res = await fetch(url, init)
    if (!res.ok) {
      let detail = ''
      try {
        detail = JSON.stringify(await res.json())
      } catch {
        try {
          detail = await res.text()
        } catch {
          /* ignore */
        }
      }
      const err = new Error(`${method} ${path} → ${res.status} ${detail}`)
      onError(err, { method, path })
      throw err
    }
    if (res.status === 204) return undefined as unknown as T
    return (await res.json()) as T
  }

  return {
    async loadAnnotations() {
      return request<PagePins>('GET', '/api/annotations')
    },

    async loadLabels() {
      return request<LabelDef[]>('GET', '/api/labels')
    },

    async loadAuthor() {
      // 작성자는 브라우저별 로컬 정체성 — 서버가 아니라 localStorage 그대로 유지
      try {
        return localStorage.getItem('cs_annot_author') ?? ''
      } catch {
        return ''
      }
    },

    async loadLastLabelId() {
      try {
        return localStorage.getItem('cs_annot_last_label_v1')
      } catch {
        return null
      }
    },

    async saveAuthor(name: string) {
      try {
        localStorage.setItem('cs_annot_author', name)
      } catch {
        /* ignore */
      }
    },

    async saveLastLabelId(id: string | null) {
      try {
        if (id == null) localStorage.removeItem('cs_annot_last_label_v1')
        else localStorage.setItem('cs_annot_last_label_v1', id)
      } catch {
        /* ignore */
      }
    },

    async loadAuthorDefaultLabelId() {
      try {
        return localStorage.getItem('cs_annot_author_default_label')
      } catch {
        return null
      }
    },

    async saveAuthorDefaultLabelId(id: string | null) {
      try {
        if (id == null) localStorage.removeItem('cs_annot_author_default_label')
        else localStorage.setItem('cs_annot_author_default_label', id)
      } catch {
        /* ignore */
      }
    },

    async createLabel(input: CreateLabelInput) {
      return request<LabelDef>('POST', '/api/labels', input)
    },

    async updateLabel(id, patch) {
      return request<LabelDef>('PATCH', `/api/labels/${encodeURIComponent(id)}`, patch)
    },

    async deleteLabel(id) {
      await request<void>('DELETE', `/api/labels/${encodeURIComponent(id)}`)
    },

    async createPin(input: CreatePinInput) {
      return request<Pin>('POST', '/api/pins', input)
    },

    async updatePin(id, patch) {
      return request<Pin>('PATCH', `/api/pins/${encodeURIComponent(id)}`, patch)
    },

    async deletePin(id) {
      await request<void>('DELETE', `/api/pins/${encodeURIComponent(id)}`)
    },

    async resolvePin(id, by) {
      return request<Pin>('POST', `/api/pins/${encodeURIComponent(id)}/resolve`, { by })
    },

    async reopenPin(id) {
      return request<Pin>('POST', `/api/pins/${encodeURIComponent(id)}/reopen`)
    },

    async addComment(pinId, author, text) {
      return request<Comment>(
        'POST',
        `/api/pins/${encodeURIComponent(pinId)}/comments`,
        { author, text }
      )
    },

    async updateComment(commentId, text) {
      return request<Comment>('PATCH', `/api/comments/${encodeURIComponent(commentId)}`, { text })
    },

    async deleteComment(commentId) {
      await request<void>('DELETE', `/api/comments/${encodeURIComponent(commentId)}`)
    },

    // ── Sessions ─────────────────────────────────────────────
    async loadSessions() {
      return request<AnnotSession[]>('GET', '/api/sessions')
    },

    async createSession(name: string, options?) {
      return request<AnnotSession>('POST', '/api/sessions', { name, ...options })
    },

    async updateSession(id: string, patch) {
      return request<AnnotSession>('PATCH', `/api/sessions/${encodeURIComponent(id)}`, patch)
    },

    async deleteSession(id: string) {
      await request<void>('DELETE', `/api/sessions/${encodeURIComponent(id)}`)
    },

    async loadCurrentSessionId() {
      try { return localStorage.getItem('cs_annot_current_session') } catch { return null }
    },

    async saveCurrentSessionId(id: string | null) {
      try {
        if (id == null) localStorage.removeItem('cs_annot_current_session')
        else localStorage.setItem('cs_annot_current_session', id)
      } catch { /* ignore */ }
    },

    async checkSdkVersion() {
      try {
        const res = await fetch(`${base}/api/sdk/version`, {
          headers: { Accept: 'application/json' },
        })
        if (!res.ok) return { latest: null, minimum: null }
        const data = await res.json()
        return { latest: data.latest ?? null, minimum: data.minimum ?? null }
      } catch {
        return { latest: null, minimum: null }
      }
    },
  }
}
