import { useState } from 'react'
import { DARK, FALLBACK_LABEL_COLOR, FONT_FAMILY } from './constants'
import type { LabelDef, Pin } from './types'

interface Props {
  pins: Pin[]
  labels: LabelDef[]
  pageId: string
  selectedId: string | null
  hoveredId?: string | null
  showResolved: boolean
  resolvedCount: number
  onSelect: (id: string) => void
  onHover?: (id: string | null) => void
  onToggleShowResolved: () => void
  onClose: () => void
}

export function AnnotList({
  pins,
  labels,
  pageId,
  selectedId,
  hoveredId,
  showResolved,
  resolvedCount,
  onSelect,
  onHover,
  onToggleShowResolved,
  onClose,
}: Props) {
  const labelById = new Map(labels.map((l) => [l.id, l]))

  const [authorFilter, setAuthorFilter] = useState<string | null>(null)
  const uniqueAuthors = Array.from(new Set(pins.map((p) => p.author).filter((a): a is string => !!a)))
  const filteredPins = authorFilter ? pins.filter((p) => p.author === authorFilter) : pins

  return (
    <div
      style={{
        position: 'fixed',
        left: 0,
        top: 0,
        bottom: 0,
        width: 252,
        background: DARK.bg,
        borderRight: `1px solid ${DARK.brd}`,
        boxShadow: '4px 0 24px rgba(0,0,0,.3)',
        zIndex: 9999,
        display: 'flex',
        flexDirection: 'column',
        fontFamily: FONT_FAMILY,
      }}
    >
      <style>{`
        .sb-scroll::-webkit-scrollbar{width:4px;height:4px}
        .sb-scroll::-webkit-scrollbar-track{background:transparent}
        .sb-scroll::-webkit-scrollbar-thumb{background:rgba(255,255,255,.14);border-radius:10px}
        .sb-scroll::-webkit-scrollbar-thumb:hover{background:rgba(255,255,255,.26)}
        .sb-scroll{scrollbar-width:thin;scrollbar-color:rgba(255,255,255,.14) transparent}
      `}</style>

      {/* 헤더 */}
      <div style={{ padding: '14px 16px', background: DARK.bg2, flexShrink: 0, borderBottom: `1px solid ${DARK.brd}` }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontSize: 12, fontWeight: 700, color: DARK.txt }}>📋 번호 목록</div>
            <div style={{ fontSize: 10, color: DARK.txL, marginTop: 2, fontFamily: 'monospace' }}>
              {pageId}
            </div>
          </div>
          <button
            onClick={onClose}
            style={{
              background: 'rgba(255,255,255,.08)',
              border: 'none',
              color: DARK.txS,
              width: 26,
              height: 26,
              borderRadius: 5,
              cursor: 'pointer',
              fontSize: 14,
            }}
          >
            ×
          </button>
        </div>

        {/* 통계 + 해결 토글 */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 10 }}>
          <span style={{ fontSize: 11, color: DARK.txL }}>총 {filteredPins.length}개</span>

          {resolvedCount > 0 && (
            <button
              onClick={onToggleShowResolved}
              title={showResolved ? '해결된 항목 숨기기' : '해결된 항목 보기'}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 4,
                padding: '3px 8px',
                borderRadius: 2,
                border: `1px solid ${showResolved ? 'rgba(22,163,74,.5)' : DARK.brd}`,
                background: showResolved ? 'rgba(22,163,74,.15)' : 'rgba(255,255,255,.04)',
                color: showResolved ? '#4ade80' : DARK.txL,
                fontSize: 10,
                fontWeight: 600,
                cursor: 'pointer',
                transition: 'all .15s',
              }}
            >
              <span style={{ fontSize: 11 }}>{showResolved ? '✓' : '○'}</span>
              <span>해결 {resolvedCount}</span>
            </button>
          )}
        </div>

        {/* 작성자 필터 */}
        {uniqueAuthors.length > 0 && (
          <div style={{ marginTop: 8 }}>
            <select
              value={authorFilter ?? ''}
              onChange={(e) => setAuthorFilter(e.target.value || null)}
              style={{
                width: '100%',
                padding: '4px 8px',
                background: DARK.bg3,
                border: `1px solid ${authorFilter ? 'rgba(59,130,246,.5)' : DARK.brd}`,
                borderRadius: 2,
                color: authorFilter ? DARK.txt : DARK.txL,
                fontSize: 11,
                cursor: 'pointer',
                outline: 'none',
                fontFamily: FONT_FAMILY,
              }}
            >
              <option value="" style={{ background: DARK.bg3, color: DARK.txL }}>전체 작성자</option>
              {uniqueAuthors.map((a) => (
                <option key={a} value={a} style={{ background: DARK.bg3, color: DARK.txt }}>{a}</option>
              ))}
            </select>
          </div>
        )}
      </div>

      {/* 목록 */}
      <div className="sb-scroll" style={{ flex: 1, overflowY: 'auto', padding: 8 }}>
        {filteredPins.length === 0 ? (
          <div
            style={{
              textAlign: 'center',
              color: DARK.txL,
              fontSize: 12,
              marginTop: 36,
              lineHeight: 1.8,
            }}
          >
            {authorFilter
              ? '선택한 작성자의 핀이 없습니다.'
              : <><br />아직 추가된 레이블이 없습니다.<br />화면을 클릭해서 추가하세요.</>
            }
          </div>
        ) : (
          filteredPins.map((p) => {
            const sel = p.id === selectedId
            const hov = p.id === hoveredId
            const label = p.labelId ? labelById.get(p.labelId) : undefined
            const color = label?.color ?? FALLBACK_LABEL_COLOR
            const resolved = p.status === 'resolved'
            return (
              <div
                key={p.id}
                onClick={() => onSelect(p.id)}
                onMouseEnter={() => onHover?.(p.id)}
                onMouseLeave={() => onHover?.(null)}
                style={{
                  padding: '10px 12px',
                  borderRadius: 2,
                  marginBottom: 4,
                  cursor: 'pointer',
                  border: `1px solid ${sel ? color : hov ? color : DARK.brd}`,
                  background: sel ? `${color}1a` : hov ? `${color}0d` : DARK.bg2,
                  display: 'flex',
                  alignItems: 'flex-start',
                  gap: 8,
                  transition: 'all .12s',
                  opacity: resolved ? 0.6 : 1,
                }}
              >
                {/* 번호 뱃지 */}
                <div
                  style={{
                    position: 'relative',
                    width: 20,
                    height: 20,
                    borderRadius: '50%',
                    background: color,
                    color: '#fff',
                    fontSize: 10,
                    fontWeight: 700,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexShrink: 0,
                  }}
                >
                  {p.num}
                  {resolved && (
                    <span
                      style={{
                        position: 'absolute',
                        top: -3,
                        right: -3,
                        width: 11,
                        height: 11,
                        borderRadius: '50%',
                        background: '#16a34a',
                        color: '#fff',
                        fontSize: 7,
                        fontWeight: 900,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        border: '1.5px solid #fff',
                      }}
                    >
                      ✓
                    </span>
                  )}
                </div>

                {/* 내용 */}
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 12, fontWeight: 600, color: DARK.txt, overflow: 'hidden' }}>
                    <span
                      style={{
                        padding: '1px 7px',
                        borderRadius: 999,
                        background: `${color}22`,
                        color,
                        fontSize: 10,
                        fontWeight: 700,
                        flexShrink: 0,
                        textDecoration: resolved ? 'line-through' : 'none',
                      }}
                    >
                      {label?.name ?? '미분류'}
                    </span>
                    {resolved && (
                      <span style={{ fontSize: 9, padding: '1px 5px', background: 'rgba(22,163,74,.2)', color: '#4ade80', borderRadius: 5, fontWeight: 700, flexShrink: 0 }}>
                        해결
                      </span>
                    )}
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginTop: 2 }}>
                    {p.author && <span style={{ fontSize: 10, color: DARK.txL }}>{p.author}</span>}
                    {p.comments.length > 0 && (
                      <span style={{ fontSize: 9, padding: '1px 5px', background: 'rgba(59,130,246,.2)', color: '#93C5FD', borderRadius: 5, fontWeight: 700 }}>
                        💬 {p.comments.length}
                      </span>
                    )}
                  </div>
                  {p.note && (
                    <div style={{ fontSize: 11, color: DARK.txL, marginTop: 2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {p.note}
                    </div>
                  )}
                </div>
              </div>
            )
          })
        )}
      </div>
    </div>
  )
}
