import { useCallback, useEffect, useMemo, useState } from 'react'
import type { Comment, PagePins, Pin, StorageAdapter } from './types'

export function useAnnotations(pageId: string, storage: StorageAdapter) {
  const [allAnnots, setAllAnnots] = useState<PagePins>({})
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let cancelled = false
    storage
      .loadAnnotations()
      .then((data) => {
        if (!cancelled) setAllAnnots(data)
      })
      .catch((e) => console.error('[specbridge] loadAnnotations failed', e))
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [storage])

  const pins = useMemo<Pin[]>(() => allAnnots[pageId] ?? [], [allAnnots, pageId])

  const replacePin = useCallback((pin: Pin) => {
    setAllAnnots((prev) => {
      const out: PagePins = {}
      for (const [pid, arr] of Object.entries(prev)) {
        out[pid] = arr.map((p) => (p.id === pin.id ? pin : p))
      }
      return out
    })
  }, [])

  const removePinEverywhere = useCallback((pinId: string) => {
    setAllAnnots((prev) => {
      const out: PagePins = {}
      for (const [pid, arr] of Object.entries(prev)) {
        out[pid] = arr.filter((p) => p.id !== pinId)
      }
      return out
    })
  }, [])

  const addPin = useCallback(
    async (
      x: number,
      y: number,
      author: string,
      labelId: string | null,
      sessionId?: string | null
    ): Promise<Pin | null> => {
      try {
        const pin = await storage.createPin({ pageId, x, y, labelId, author, sessionId })
        setAllAnnots((prev) => ({
          ...prev,
          [pageId]: [...(prev[pageId] ?? []), pin],
        }))
        return pin
      } catch (e) {
        console.error('[specbridge] createPin failed', e)
        return null
      }
    },
    [pageId, storage]
  )

  const updatePin = useCallback(
    async (id: string, patch: Partial<Omit<Pin, 'id' | 'comments'>>) => {
      try {
        const pin = await storage.updatePin(id, patch)
        replacePin(pin)
      } catch (e) {
        console.error('[specbridge] updatePin failed', e)
      }
    },
    [storage, replacePin]
  )

  const deletePin = useCallback(
    async (id: string) => {
      try {
        await storage.deletePin(id)
        removePinEverywhere(id)
      } catch (e) {
        console.error('[specbridge] deletePin failed', e)
      }
    },
    [storage, removePinEverywhere]
  )

  const movePin = useCallback(
    async (id: string, pos: { x: number; y: number }) => {
      try {
        const pin = await storage.updatePin(id, pos)
        replacePin(pin)
      } catch (e) {
        console.error('[specbridge] movePin failed', e)
      }
    },
    [storage, replacePin]
  )

  const resolvePin = useCallback(
    async (id: string, by: string) => {
      try {
        const pin = await storage.resolvePin(id, by)
        replacePin(pin)
      } catch (e) {
        console.error('[specbridge] resolvePin failed', e)
      }
    },
    [storage, replacePin]
  )

  const reopenPin = useCallback(
    async (id: string) => {
      try {
        const pin = await storage.reopenPin(id)
        replacePin(pin)
      } catch (e) {
        console.error('[specbridge] reopenPin failed', e)
      }
    },
    [storage, replacePin]
  )

  const addComment = useCallback(
    async (pinId: string, author: string, text: string): Promise<Comment | null> => {
      try {
        const comment = await storage.addComment(pinId, author, text)
        setAllAnnots((prev) => {
          const out: PagePins = {}
          for (const [pid, arr] of Object.entries(prev)) {
            out[pid] = arr.map((p) =>
              p.id === pinId ? { ...p, comments: [...p.comments, comment] } : p
            )
          }
          return out
        })
        return comment
      } catch (e) {
        console.error('[specbridge] addComment failed', e)
        return null
      }
    },
    [storage]
  )

  const updateComment = useCallback(
    async (pinId: string, commentId: string, text: string) => {
      try {
        const comment = await storage.updateComment(commentId, text)
        setAllAnnots((prev) => {
          const out: PagePins = {}
          for (const [pid, arr] of Object.entries(prev)) {
            out[pid] = arr.map((p) =>
              p.id === pinId
                ? { ...p, comments: p.comments.map((c) => (c.id === commentId ? comment : c)) }
                : p
            )
          }
          return out
        })
      } catch (e) {
        console.error('[specbridge] updateComment failed', e)
      }
    },
    [storage]
  )

  const deleteComment = useCallback(
    async (pinId: string, commentId: string) => {
      try {
        await storage.deleteComment(commentId)
        setAllAnnots((prev) => {
          const out: PagePins = {}
          for (const [pid, arr] of Object.entries(prev)) {
            out[pid] = arr.map((p) =>
              p.id === pinId
                ? { ...p, comments: p.comments.filter((c) => c.id !== commentId) }
                : p
            )
          }
          return out
        })
      } catch (e) {
        console.error('[specbridge] deleteComment failed', e)
      }
    },
    [storage]
  )

  return {
    loading,
    allAnnots,
    pins,
    addPin,
    updatePin,
    deletePin,
    movePin,
    addComment,
    updateComment,
    deleteComment,
    resolvePin,
    reopenPin,
  }
}
