import { DEFAULT_LABELS, STORAGE_KEYS } from './constants'
import type {
  AnnotSession,
  Comment,
  CreateLabelInput,
  CreatePinInput,
  LabelDef,
  PagePins,
  Pin,
  StorageAdapter,
} from './types'

const loadJson = <T,>(key: string, fallback: T): T => {
  try {
    const raw = localStorage.getItem(key)
    if (raw == null) return fallback
    const parsed = JSON.parse(raw)
    return (parsed ?? fallback) as T
  } catch {
    return fallback
  }
}

const saveJson = (key: string, value: unknown): void => {
  try {
    localStorage.setItem(key, JSON.stringify(value))
  } catch {
    // ignore
  }
}

function genId(prefix = '') {
  return `${prefix}${Date.now()}-${Math.random().toString(36).slice(2, 6)}`
}

function readAll(): PagePins {
  return loadJson<PagePins>(STORAGE_KEYS.annotations, {})
}
function writeAll(data: PagePins) {
  saveJson(STORAGE_KEYS.annotations, data)
}
function readSessions(): AnnotSession[] {
  return loadJson<AnnotSession[]>(STORAGE_KEYS.sessions, [])
}
function writeSessions(sessions: AnnotSession[]) {
  saveJson(STORAGE_KEYS.sessions, sessions)
}

function readLabels(): LabelDef[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEYS.labels)
    if (raw == null) return DEFAULT_LABELS
    const parsed = JSON.parse(raw) as unknown
    if (Array.isArray(parsed)) return parsed as LabelDef[]
  } catch {
    // ignore
  }
  return DEFAULT_LABELS
}
function writeLabels(labels: LabelDef[]) {
  saveJson(STORAGE_KEYS.labels, labels)
}

function replacePinEverywhere(data: PagePins, pinId: string, mutator: (p: Pin) => Pin): PagePins {
  const out: PagePins = {}
  for (const [pageId, arr] of Object.entries(data)) {
    out[pageId] = arr.map((p) => (p.id === pinId ? mutator(p) : p))
  }
  return out
}

async function updatePinLocal(id: string, patch: Partial<Omit<Pin, 'id' | 'comments'>>): Promise<Pin> {
  const data = readAll()
  let updated: Pin | null = null
  const next = replacePinEverywhere(data, id, (p) => {
    updated = { ...p, ...patch }
    return updated
  })
  writeAll(next)
  if (!updated) throw new Error(`pin not found: ${id}`)
  return updated
}

/**
 * 기본 어댑터 — 브라우저 localStorage 사용 (오프라인/로컬 데모에 적합).
 * 실제 서버 연동은 `httpAdapter` 사용 권장.
 */
export const localStorageAdapter: StorageAdapter = {
  async loadAnnotations() {
    const data = readAll()
    // 기존 데이터에 num 없는 핀 backfill (로컬스토리지 마이그레이션)
    const allPins = Object.values(data).flat()
    const hasUnnum = allPins.some((p) => !p.num)
    if (hasUnnum) {
      let maxNum = allPins.reduce((m, p) => Math.max(m, p.num ?? 0), 0)
      // created_at 순으로 정렬 후 번호 부여
      const unnum = allPins
        .filter((p) => !p.num)
        .sort((a, b) => a.createdAt.localeCompare(b.createdAt))
      for (const p of unnum) p.num = ++maxNum
      writeAll(data)
    }
    return data
  },

  async loadLabels() {
    return readLabels()
  },

  async loadAuthor() {
    try {
      return localStorage.getItem(STORAGE_KEYS.author) ?? ''
    } catch {
      return ''
    }
  },

  async loadLastLabelId() {
    try {
      return localStorage.getItem(STORAGE_KEYS.lastLabel)
    } catch {
      return null
    }
  },

  async saveAuthor(name) {
    try {
      localStorage.setItem(STORAGE_KEYS.author, name)
    } catch {
      // ignore
    }
  },

  async saveLastLabelId(id) {
    try {
      if (id == null) localStorage.removeItem(STORAGE_KEYS.lastLabel)
      else localStorage.setItem(STORAGE_KEYS.lastLabel, id)
    } catch {
      // ignore
    }
  },

  async loadAuthorDefaultLabelId() {
    try {
      return localStorage.getItem(STORAGE_KEYS.defaultLabel)
    } catch {
      return null
    }
  },

  async saveAuthorDefaultLabelId(id) {
    try {
      if (id == null) localStorage.removeItem(STORAGE_KEYS.defaultLabel)
      else localStorage.setItem(STORAGE_KEYS.defaultLabel, id)
    } catch {
      // ignore
    }
  },

  async createLabel({ name, color }: CreateLabelInput) {
    const label: LabelDef = { id: genId('lbl-'), name: name.trim(), color }
    const labels = readLabels()
    writeLabels([...labels, label])
    return label
  },

  async updateLabel(id, patch) {
    const labels = readLabels()
    const next = labels.map((l) =>
      l.id === id ? { ...l, ...patch, name: patch.name?.trim() ?? l.name } : l
    )
    writeLabels(next)
    const found = next.find((l) => l.id === id)
    if (!found) throw new Error(`label not found: ${id}`)
    return found
  },

  async deleteLabel(id) {
    const labels = readLabels()
    writeLabels(labels.filter((l) => l.id !== id))
  },

  async createPin({ pageId, x, y, labelId, author, sessionId }: CreatePinInput) {
    const data = readAll()
    // 전체 프로젝트(모든 페이지) 기준 최대 num + 1
    const maxNum = Object.values(data).flat().reduce((m, p) => Math.max(m, p.num ?? 0), 0)
    const pin: Pin = {
      id: genId(),
      num: maxNum + 1,
      x,
      y,
      labelId,
      note: '',
      author,
      createdAt: new Date().toISOString(),
      status: 'open',
      comments: [],
      sessionId: sessionId ?? null,
    }
    data[pageId] = [...(data[pageId] ?? []), pin]
    writeAll(data)
    return pin
  },

  async updatePin(id, patch) {
    return updatePinLocal(id, patch)
  },

  async deletePin(id) {
    const data = readAll()
    const out: PagePins = {}
    for (const [pageId, arr] of Object.entries(data)) {
      out[pageId] = arr.filter((p) => p.id !== id)
    }
    writeAll(out)
  },

  async resolvePin(id, by) {
    return updatePinLocal(id, {
      status: 'resolved',
      resolvedBy: by,
      resolvedAt: new Date().toISOString(),
    })
  },

  async reopenPin(id) {
    return updatePinLocal(id, {
      status: 'open',
      resolvedBy: undefined,
      resolvedAt: undefined,
    })
  },

  async addComment(pinId, author, text) {
    const comment: Comment = {
      id: genId('c-'),
      author,
      text: text.trim(),
      createdAt: new Date().toISOString(),
    }
    const data = readAll()
    const next = replacePinEverywhere(data, pinId, (p) => ({
      ...p,
      comments: [...p.comments, comment],
    }))
    writeAll(next)
    return comment
  },

  async updateComment(commentId, text) {
    const data = readAll()
    let updated: Comment | null = null
    const next: PagePins = {}
    for (const [pageId, arr] of Object.entries(data)) {
      next[pageId] = arr.map((p) => ({
        ...p,
        comments: p.comments.map((c) => {
          if (c.id !== commentId) return c
          updated = { ...c, text: text.trim(), updatedAt: new Date().toISOString() }
          return updated
        }),
      }))
    }
    writeAll(next)
    if (!updated) throw new Error(`comment not found: ${commentId}`)
    return updated
  },

  async deleteComment(commentId) {
    const data = readAll()
    const next: PagePins = {}
    for (const [pageId, arr] of Object.entries(data)) {
      next[pageId] = arr.map((p) => ({
        ...p,
        comments: p.comments.filter((c) => c.id !== commentId),
      }))
    }
    writeAll(next)
  },

  // ── Sessions ─────────────────────────────────────────────
  async loadSessions() {
    return readSessions()
  },

  async createSession(name, options) {
    const session: AnnotSession = {
      id: genId('ses-'),
      name: name.trim(),
      createdAt: new Date().toISOString(),
      status: 'active',
      viewport: options?.viewport ?? null,
      note: options?.note ?? null,
    }
    writeSessions([...readSessions(), session])
    return session
  },

  async updateSession(id, patch) {
    const sessions = readSessions()
    const next = sessions.map((s) =>
      s.id === id
        ? { ...s, ...patch, ...(patch.name ? { name: patch.name.trim() } : {}) }
        : s
    )
    writeSessions(next)
    const found = next.find((s) => s.id === id)
    if (!found) throw new Error(`session not found: ${id}`)
    return found
  },

  async deleteSession(id) {
    writeSessions(readSessions().filter((s) => s.id !== id))
  },

  async loadCurrentSessionId() {
    try { return localStorage.getItem(STORAGE_KEYS.currentSession) } catch { return null }
  },

  async saveCurrentSessionId(id) {
    try {
      if (id == null) localStorage.removeItem(STORAGE_KEYS.currentSession)
      else localStorage.setItem(STORAGE_KEYS.currentSession, id)
    } catch { /* ignore */ }
  },
}
