import type { CSSProperties, ReactNode } from 'react'

interface Props {
  children: string
  theme?: 'light' | 'dark'
  style?: CSSProperties
}

// ── 색상명 → hex ───────────────────────────────────────────
const COLOR_MAP: Record<string, string> = {
  red:    '#ef4444',
  green:  '#34D399',
  blue:   '#60A5FA',
  yellow: '#FCD34D',
  orange: '#FB923C',
  purple: '#A78BFA',
  pink:   '#F472B6',
  gray:   '#9CA3AF',
}

// ── Inline parser ──────────────────────────────────────────
function parseInline(text: string, theme: 'light' | 'dark'): ReactNode {
  const codeStyle: CSSProperties =
    theme === 'dark'
      ? { background: 'rgba(255,255,255,.13)', padding: '1px 5px', borderRadius: 3, fontFamily: 'monospace', fontSize: '0.88em' }
      : { background: 'rgba(0,0,0,.07)', padding: '1px 5px', borderRadius: 3, fontFamily: 'monospace', fontSize: '0.88em' }

  const parts: ReactNode[] = []
  let i = 0
  let buf = ''
  let keyN = 0

  const flush = () => {
    if (buf) { parts.push(buf); buf = '' }
  }

  while (i < text.length) {
    // Bold **...**
    if (text[i] === '*' && text[i + 1] === '*') {
      const end = text.indexOf('**', i + 2)
      if (end !== -1) {
        flush()
        parts.push(<strong key={keyN++}>{text.slice(i + 2, end)}</strong>)
        i = end + 2; continue
      }
    }
    // Italic *...*
    if (text[i] === '*' && text[i + 1] !== '*') {
      const end = text.indexOf('*', i + 1)
      if (end !== -1) {
        flush()
        parts.push(<em key={keyN++}>{text.slice(i + 1, end)}</em>)
        i = end + 1; continue
      }
    }
    // Bold __...__
    if (text[i] === '_' && text[i + 1] === '_') {
      const end = text.indexOf('__', i + 2)
      if (end !== -1) {
        flush()
        parts.push(<strong key={keyN++}>{text.slice(i + 2, end)}</strong>)
        i = end + 2; continue
      }
    }
    // Italic _..._
    if (text[i] === '_' && text[i + 1] !== '_') {
      const end = text.indexOf('_', i + 1)
      if (end !== -1) {
        flush()
        parts.push(<em key={keyN++}>{text.slice(i + 1, end)}</em>)
        i = end + 1; continue
      }
    }
    // Inline code `...`
    if (text[i] === '`') {
      const end = text.indexOf('`', i + 1)
      if (end !== -1) {
        flush()
        parts.push(<code key={keyN++} style={codeStyle}>{text.slice(i + 1, end)}</code>)
        i = end + 1; continue
      }
    }
    // Color {color:text}
    if (text[i] === '{') {
      const colon = text.indexOf(':', i + 1)
      const close = text.indexOf('}', i + 1)
      if (colon !== -1 && close !== -1 && colon < close) {
        const colorKey = text.slice(i + 1, colon).trim()
        const colorVal = COLOR_MAP[colorKey] ?? (colorKey.startsWith('#') ? colorKey : null)
        if (colorVal) {
          flush()
          parts.push(
            <span key={keyN++} style={{ color: colorVal }}>
              {text.slice(colon + 1, close)}
            </span>
          )
          i = close + 1; continue
        }
      }
    }
    // Link [text](url)
    if (text[i] === '[') {
      const cb = text.indexOf(']', i + 1)
      if (cb !== -1 && text[cb + 1] === '(') {
        const cp = text.indexOf(')', cb + 2)
        if (cp !== -1) {
          flush()
          parts.push(
            <a key={keyN++} href={text.slice(cb + 2, cp)} target="_blank" rel="noopener noreferrer"
              style={{ color: 'inherit', textDecoration: 'underline' }}>
              {text.slice(i + 1, cb)}
            </a>
          )
          i = cp + 1; continue
        }
      }
    }
    buf += text[i]; i++
  }
  flush()
  return parts.length === 1 ? parts[0] : <>{parts}</>
}

// ── Block renderer ─────────────────────────────────────────
export function Markdown({ children, theme = 'light', style }: Props) {
  const isDark = theme === 'dark'
  const t = theme

  const codeBlockStyle: CSSProperties = {
    display: 'block',
    background: isDark ? 'rgba(0,0,0,.3)' : '#f3f4f6',
    color: isDark ? '#e2e8f0' : '#374151',
    padding: '8px 10px',
    borderRadius: 6,
    fontFamily: 'monospace',
    fontSize: '0.85em',
    whiteSpace: 'pre',
    overflowX: 'auto',
    margin: '4px 0',
  }

  const blockquoteStyle: CSSProperties = {
    borderLeft: `3px solid ${isDark ? 'rgba(255,255,255,.28)' : '#d1d5db'}`,
    margin: '3px 0',
    paddingLeft: 10,
    color: isDark ? 'rgba(255,255,255,.48)' : '#6b7280',
    fontStyle: 'italic',
  }

  const hrStyle: CSSProperties = {
    border: 'none',
    borderTop: `1px solid ${isDark ? 'rgba(255,255,255,.18)' : '#e5e7eb'}`,
    margin: '8px 0',
  }

  const lines = children.split('\n')
  const elements: ReactNode[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Code fence ```
    if (line.trimStart().startsWith('```')) {
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].trimStart().startsWith('```')) {
        codeLines.push(lines[i])
        i++
      }
      elements.push(
        <pre key={`cb${i}`} style={codeBlockStyle}>
          <code>{codeLines.join('\n')}</code>
        </pre>
      )
      i++; continue
    }

    // Horizontal rule
    if (/^-{3,}$/.test(line.trim()) || /^\*{3,}$/.test(line.trim())) {
      elements.push(<hr key={`hr${i}`} style={hrStyle} />)
      i++; continue
    }

    // Headings # ## ###
    const hm = line.match(/^(#{1,3})\s+(.+)/)
    if (hm) {
      const level = hm[1].length
      const sizes = [17, 14, 13]
      const marginTops = [8, 6, 4]
      elements.push(
        <div key={`h${i}`} style={{ fontSize: sizes[level - 1], fontWeight: 700, margin: `${marginTops[level - 1]}px 0 2px`, lineHeight: 1.3 }}>
          {parseInline(hm[2], t)}
        </div>
      )
      i++; continue
    }

    // Blockquote >
    if (line.startsWith('>')) {
      const text = line.replace(/^>\s?/, '')
      elements.push(<div key={`bq${i}`} style={blockquoteStyle}>{parseInline(text, t)}</div>)
      i++; continue
    }

    // Unordered list - / *
    if (/^(\s*)[-*]\s+/.test(line)) {
      const items: ReactNode[] = []
      while (i < lines.length && /^(\s*)[-*]\s+/.test(lines[i])) {
        const m = lines[i].match(/^(\s*)[-*]\s+(.+)/)
        if (m) items.push(<li key={`li${i}`} style={{ marginBottom: 1 }}>{parseInline(m[2], t)}</li>)
        i++
      }
      elements.push(
        <ul key={`ul${i}`} style={{ margin: '3px 0', paddingLeft: 18, lineHeight: 1.6 }}>
          {items}
        </ul>
      )
      continue
    }

    // Ordered list 1.
    if (/^\d+\.\s+/.test(line)) {
      const items: ReactNode[] = []
      while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
        const m = lines[i].match(/^\d+\.\s+(.+)/)
        if (m) items.push(<li key={`li${i}`} style={{ marginBottom: 1 }}>{parseInline(m[1], t)}</li>)
        i++
      }
      elements.push(
        <ol key={`ol${i}`} style={{ margin: '3px 0', paddingLeft: 18, lineHeight: 1.6 }}>
          {items}
        </ol>
      )
      continue
    }

    // Empty line → small gap
    if (line.trim() === '') {
      elements.push(<div key={`sp${i}`} style={{ height: 6 }} />)
      i++; continue
    }

    // Paragraph
    elements.push(
      <div key={`p${i}`} style={{ lineHeight: 1.65 }}>
        {parseInline(line, t)}
      </div>
    )
    i++
  }

  return <div style={style}>{elements}</div>
}
