import { useCallback, useEffect, useState } from 'react'
import type { LabelDef, StorageAdapter } from './types'

export function useLabels(storage: StorageAdapter) {
  const [labels, setLabels] = useState<LabelDef[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let cancelled = false
    storage
      .loadLabels()
      .then((v) => {
        if (!cancelled) setLabels(v)
      })
      .catch((e) => console.error('[specbridge] loadLabels failed', e))
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [storage])

  const addLabel = useCallback(
    async (name: string, color: string): Promise<LabelDef | null> => {
      try {
        const trimmed = name.trim()
        if (!trimmed) return null
        const created = await storage.createLabel({ name: trimmed, color })
        setLabels((prev) => [...prev, created])
        return created
      } catch (e) {
        console.error('[specbridge] createLabel failed', e)
        return null
      }
    },
    [storage]
  )

  const updateLabel = useCallback(
    async (id: string, patch: Partial<Omit<LabelDef, 'id'>>) => {
      try {
        const updated = await storage.updateLabel(id, patch)
        setLabels((prev) => prev.map((l) => (l.id === id ? updated : l)))
      } catch (e) {
        console.error('[specbridge] updateLabel failed', e)
      }
    },
    [storage]
  )

  const deleteLabel = useCallback(
    async (id: string) => {
      try {
        await storage.deleteLabel(id)
        setLabels((prev) => prev.filter((l) => l.id !== id))
      } catch (e) {
        console.error('[specbridge] deleteLabel failed', e)
      }
    },
    [storage]
  )

  return { labels, addLabel, updateLabel, deleteLabel, loading }
}
