const SPOTLIGHT_PADDING = 8

interface SpotRect { top: number; left: number; width: number; height: number }

function getSpotRect(target: string | null): SpotRect | null {
  if (!target) return null
  const el = document.querySelector(`[data-guide="${target}"]`)
  if (!el) return null
  const r = el.getBoundingClientRect()
  return { top: r.top, left: r.left, width: r.width, height: r.height }
}

interface Props {
  onClose: (forever: boolean) => void
}

export function OnboardingGuide({ onClose }: Props) {
  const [step, setStep] = useState(0)
  const [hideForever, setHideForever] = useState(false)
  const [spotRect, setSpotRect] = useState<SpotRect | null>(null)
  const isLast = step === STEPS.length - 1
  const current = STEPS[step]

  // 스텝 변경 시 타겟 엘리먼트 위치 계산
  useEffect(() => {
    // requestAnimationFrame으로 DOM 렌더 후 측정
    const raf = requestAnimationFrame(() => {
      setSpotRect(getSpotRect(current.target))
    })
    return () => cancelAnimationFrame(raf)
  }, [step, current.target])

  // 윈도우 리사이즈 시 재계산
  useEffect(() => {
    const onResize = () => setSpotRect(getSpotRect(current.target))
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [current.target])

  const handleClose = () => {
    if (hideForever) markDismissedForever()
    onClose(hideForever)
  }

  const handleNext = () => {
    if (isLast) { handleClose(); return }
    setStep((v) => v + 1)
  }

  const handlePrev = () => setStep((v) => v - 1)

  return (
    <>
      {/* ── 클릭 오버레이 (딤 or 투명) ── */}
      <div
        onClick={handleClose}
        style={{
          position: 'fixed',
          inset: 0,
          zIndex: 19996,
          background: spotRect ? 'transparent' : 'rgba(0,0,0,.70)',
          fontFamily: FONT_FAMILY,
        }}
      />

      {/* ── 스포트라이트 링 ── */}
      {spotRect && (
        <div
          style={{
            position: 'fixed',
            top: spotRect.top - SPOTLIGHT_PADDING,
            left: spotRect.left - SPOTLIGHT_PADDING,
            width: spotRect.width + SPOTLIGHT_PADDING * 2,
            height: spotRect.height + SPOTLIGHT_PADDING * 2,
            borderRadius: 10,
            boxShadow: '0 0 0 9999px rgba(0,0,0,.70)',
            border: '2px solid rgba(59,130,246,.75)',
            zIndex: 19997,
            transition: 'top .3s cubic-bezier(.4,0,.2,1), left .3s cubic-bezier(.4,0,.2,1), width .3s cubic-bezier(.4,0,.2,1), height .3s cubic-bezier(.4,0,.2,1)',
            pointerEvents: 'none',
          }}
        />
      )}

      {/* ── 가이드 카드 (중앙 고정) ── */}
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          position: 'fixed',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          zIndex: 19999,
          background: 'rgba(12,12,12,.98)',
          border: '1px solid rgba(255,255,255,.1)',
          borderRadius: 16,
          padding: '20px 26px 18px',
          width: 340,
          height: 390,
          maxHeight: 'calc(100vh - 48px)',
          display: 'flex',
          flexDirection: 'column',
          overflowY: 'auto',
          boxShadow: '0 32px 80px rgba(0,0,0,.75)',
          fontFamily: FONT_FAMILY,
        }}
      >
        {/* 닫기 버튼 */}
        <button
          onClick={handleClose}
          style={{
            position: 'absolute', top: 13, right: 14,
            background: 'transparent', border: 'none',
            color: 'rgba(255,255,255,.28)', fontSize: 15,
            cursor: 'pointer', lineHeight: 1, padding: 4,
          }}
        >✕</button>

        {/* 스텝 인디케이터 */}
        <div style={{ display: 'flex', gap: 5, justifyContent: 'center', marginBottom: 14, flexShrink: 0 }}>
          {STEPS.map((_, i) => (
            <div
              key={i}
              onClick={() => setStep(i)}
              style={{
                width: i === step ? 20 : 6,
                height: 6,
                borderRadius: 3,
                background: i === step ? '#3B82F6' : 'rgba(255,255,255,.16)',
                cursor: 'pointer',
                transition: 'all .22s',
              }}
            />
          ))}
        </div>

        {/* 아이콘 */}
        <div style={{ height: 68, marginTop: 20, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
          {current.icon}
        </div>

        {/* 제목 */}
        <div style={{
          textAlign: 'center', fontSize: step === 0 ? 20 : 16, fontWeight: 700,
          color: 'rgba(255,255,255,.92)', marginBottom: 8, lineHeight: 1.3, flexShrink: 0,
        }}>
          {current.title}
        </div>
        {/* 카테고리 badge */}
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 8, flexShrink: 0 }}>
          {step === 0 ? (
            <span style={{
              fontSize: 10, fontWeight: 600, letterSpacing: '.6px',
              color: '#6B82F6', background: 'rgba(107,130,246,.15)',
              border: '1px solid rgba(107,130,246,.3)',
              borderRadius: 20, padding: '3px 10px',
              fontFamily: FONT_FAMILY,
            }}>{current.badge}</span>
          ) : (
            <span style={{
              fontSize: 10, fontWeight: 500, letterSpacing: '.4px',
              color: 'rgba(255,255,255,.28)', background: 'rgba(255,255,255,.06)',
              border: '1px solid rgba(255,255,255,.1)',
              borderRadius: 20, padding: '3px 10px',
              fontFamily: FONT_FAMILY,
            }}>{current.badge}</span>
          )}
        </div>

        {/* 설명 */}
        <div style={{
          flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
          textAlign: 'center', fontSize: 12.5, color: 'rgba(255,255,255,.48)',
          lineHeight: 1.75,
        }}>
          {current.desc}
        </div>

        {/* 스텝 표시 */}
        <div style={{ textAlign: 'center', fontSize: 10, color: 'rgba(255,255,255,.22)', marginBottom: 10, flexShrink: 0 }}>
          {step + 1} / {STEPS.length}
        </div>

        {/* 이전 / 다음 버튼 */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 10, flexShrink: 0 }}>
          {step > 0 && (
            <button
              onClick={handlePrev}
              style={{
                flex: 1, padding: '9px 0', borderRadius: 8,
                background: 'transparent', border: '1px solid rgba(255,255,255,.1)',
                color: 'rgba(255,255,255,.4)', fontSize: 12, cursor: 'pointer',
                fontFamily: FONT_FAMILY,
              }}
            >이전</button>
          )}
          <button
            onClick={handleNext}
            style={{
              flex: 2, padding: '9px 0', borderRadius: 8,
              background: '#3B82F6', border: 'none',
              color: '#fff', fontSize: 12, fontWeight: 600,
              cursor: 'pointer', fontFamily: FONT_FAMILY,
              transition: 'background .15s',
            }}
            onMouseEnter={(e) => { e.currentTarget.style.background = '#2563EB' }}
            onMouseLeave={(e) => { e.currentTarget.style.background = '#3B82F6' }}
          >
            {isLast ? '시작하기 🚀' : '다음'}
          </button>
        </div>

        {/* 다시 보지 않음 */}
        <label
          style={{
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            gap: 7, cursor: 'pointer', userSelect: 'none', flexShrink: 0,
          }}
        >
          <input
            type="checkbox"
            checked={hideForever}
            onChange={(e) => setHideForever(e.target.checked)}
            style={{ width: 13, height: 13, cursor: 'pointer', accentColor: '#3B82F6' }}
          />
          <span style={{ fontSize: 11, color: 'rgba(255,255,255,.28)', fontFamily: FONT_FAMILY }}>
            앞으로 보이지 않음
          </span>
        </label>
      </div>
    </>
  )
}
