import { useEffect, useRef, useState } from 'react'
import { COLORS as C, DARK, FALLBACK_LABEL_COLOR, FONT_FAMILY } from './constants'
import type { LabelDef } from './types'

interface Props {
  currentAuthor: string
  currentDefaultLabelId: string | null
  labels: LabelDef[]
  onSave: (name: string, defaultLabelId: string | null) => void
  onCancel: () => void
}

export function AuthorModal({
  currentAuthor,
  currentDefaultLabelId,
  labels,
  onSave,
  onCancel,
}: Props) {
  const [name, setName] = useState(currentAuthor)
  const [selectedLabelId, setSelectedLabelId] = useState<string | null>(
    currentDefaultLabelId ?? labels[0]?.id ?? null
  )
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    const id = window.setTimeout(() => inputRef.current?.focus(), 50)
    return () => window.clearTimeout(id)
  }, [])

  useEffect(() => {
    if (!selectedLabelId && labels.length > 0) {
      setSelectedLabelId(labels[0].id)
    }
  }, [labels, selectedLabelId])

  const handleSave = () => {
    if (!name.trim()) return
    onSave(name.trim(), selectedLabelId)
  }

  const activeLabel = labels.find((l) => l.id === selectedLabelId)

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 11000,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'rgba(0,0,0,.55)',
        fontFamily: FONT_FAMILY,
      }}
    >
      <div
        style={{
          background: DARK.bg,
          border: `1px solid ${DARK.brd}`,
          borderRadius: 14,
          padding: '28px 32px',
          width: 360,
          boxShadow: '0 20px 60px rgba(0,0,0,.5)',
        }}
      >
        <div style={{ fontSize: 16, fontWeight: 700, marginBottom: 5, color: DARK.txt }}>작성자 등록</div>
        <div style={{ fontSize: 12, color: DARK.txS, marginBottom: 20 }}>
          이름과 기본 레이블은 이 브라우저에서 계속 유지됩니다.
        </div>

        {/* 이름 */}
        <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: DARK.txS, marginBottom: 5 }}>
          이름
        </label>
        <input
          ref={inputRef}
          value={name}
          onChange={(e) => {
            const v = e.target.value
            const hasKorean = /[\uAC00-\uD7AF\u1100-\u11FF\u3130-\u318F]/.test(v)
            const limit = hasKorean ? 5 : 10
            if (v.length <= limit) setName(v)
          }}
          onKeyDown={(e) => { if (e.key === 'Enter' && name.trim()) handleSave() }}
          placeholder="이름을 입력하세요 (한글 5자 / 영문 10자)"
          style={{
            width: '100%',
            padding: '10px 12px',
            border: `1px solid ${DARK.brd2}`,
            borderRadius: 8,
            fontSize: 13,
            outline: 'none',
            boxSizing: 'border-box',
            marginBottom: 20,
            background: DARK.bg3,
            color: DARK.txt,
            fontFamily: FONT_FAMILY,
          }}
        />

        {/* 기본 레이블 */}
        <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: DARK.txS, marginBottom: 8 }}>
          기본 레이블
          <span style={{ fontWeight: 400, color: DARK.txL, marginLeft: 6 }}>
            (번호 추가 시 자동 선택)
          </span>
        </label>

        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 16 }}>
          {labels.map((l) => {
            const active = selectedLabelId === l.id
            const color = l.color || FALLBACK_LABEL_COLOR
            return (
              <button
                key={l.id}
                onClick={() => setSelectedLabelId(l.id)}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 5,
                  padding: '6px 13px',
                  borderRadius: 20,
                  border: `1.5px solid ${active ? color : DARK.brd}`,
                  background: active ? `${color}22` : DARK.bg2,
                  color: active ? color : DARK.txS,
                  fontSize: 12,
                  fontWeight: active ? 700 : 400,
                  cursor: 'pointer',
                  transition: 'all .12s',
                }}
              >
                <span style={{ width: 8, height: 8, borderRadius: '50%', background: color, flexShrink: 0 }} />
                {l.name}
                {active && <span style={{ fontSize: 11 }}>✓</span>}
              </button>
            )
          })}
        </div>

        {/* 선택된 레이블 미리보기 */}
        {activeLabel && (
          <div
            style={{
              padding: '8px 12px',
              borderRadius: 8,
              background: `${activeLabel.color}12`,
              border: `1px solid ${activeLabel.color}30`,
              fontSize: 11,
              color: DARK.txS,
              marginBottom: 20,
              display: 'flex',
              alignItems: 'center',
              gap: 6,
            }}
          >
            <span style={{ width: 8, height: 8, borderRadius: '50%', background: activeLabel.color, flexShrink: 0 }} />
            번호 추가 시 기본으로&nbsp;
            <span style={{ color: activeLabel.color, fontWeight: 700 }}>{activeLabel.name}</span>
            &nbsp;레이블이 선택됩니다.
          </div>
        )}

        <div style={{ display: 'flex', gap: 8 }}>
          <button
            onClick={onCancel}
            style={{
              flex: 1,
              padding: '9px 0',
              border: `1px solid ${DARK.brd}`,
              borderRadius: 8,
              background: DARK.bg2,
              fontSize: 13,
              cursor: 'pointer',
              color: DARK.txS,
              fontFamily: FONT_FAMILY,
            }}
          >
            취소
          </button>
          <button
            onClick={handleSave}
            disabled={!name.trim()}
            style={{
              flex: 2,
              padding: '9px 0',
              border: 'none',
              borderRadius: 8,
              background: name.trim() ? C.pri : DARK.bg2,
              color: name.trim() ? '#fff' : DARK.txL,
              fontSize: 13,
              fontWeight: 600,
              cursor: name.trim() ? 'pointer' : 'not-allowed',
              transition: 'background .15s',
              fontFamily: FONT_FAMILY,
            }}
          >
            등록
          </button>
        </div>
      </div>
    </div>
  )
}
