import { useCallback, useEffect, useState } from 'react'
import type { StorageAdapter } from './types'

export function useAuthor(storage: StorageAdapter) {
  const [author, setAuthorState] = useState<string>('')
  const [defaultLabelId, setDefaultLabelIdState] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let cancelled = false
    Promise.all([
      storage.loadAuthor(),
      storage.loadAuthorDefaultLabelId?.() ?? Promise.resolve(null),
    ])
      .then(([name, labelId]) => {
        if (!cancelled) {
          setAuthorState(name)
          setDefaultLabelIdState(labelId)
        }
      })
      .catch((e) => console.error('[specbridge] useAuthor load failed', e))
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [storage])

  const setAuthor = useCallback(
    async (name: string) => {
      setAuthorState(name)
      try {
        await storage.saveAuthor(name)
      } catch (e) {
        console.error('[specbridge] saveAuthor failed', e)
      }
    },
    [storage]
  )

  const setDefaultLabelId = useCallback(
    async (id: string | null) => {
      setDefaultLabelIdState(id)
      try {
        await storage.saveAuthorDefaultLabelId?.(id)
      } catch (e) {
        console.error('[specbridge] saveAuthorDefaultLabelId failed', e)
      }
    },
    [storage]
  )

  return { author, setAuthor, defaultLabelId, setDefaultLabelId, loading }
}
