import { useCallback, useEffect, useMemo, useRef, useState, type ReactNode } from 'react'
import { AnnotList } from './AnnotList'
import { AnnotPanel } from './AnnotPanel'
import { AnnotPin } from './AnnotPin'
import { AnnotationToolbar } from './AnnotationToolbar'
import { AuthorModal } from './AuthorModal'
import { LabelManagerModal } from './LabelManagerModal'
import { OnboardingGuide, hasDismissedForever } from './OnboardingGuide'
import { localStorageAdapter } from './storage'
import type { ExportPayload, Pin, SessionViewport, StorageAdapter } from './types'
import { useAnnotations } from './useAnnotations'
import { useAuthor } from './useAuthor'
import { useLabels } from './useLabels'
import { useSessions } from './useSessions'

const LAYER_ID = 'specbridge-annot-layer'
const CONTAINER_ID = 'specbridge-annot-container'
const LOGO_TIP_KEY = 'cs_annot_logo_tip_v1'
function hasShownLogoTip(): boolean {
  try { return localStorage.getItem(LOGO_TIP_KEY) === '1' } catch { return false }
}
function markLogoTipShown(): void {
  try { localStorage.setItem(LOGO_TIP_KEY, '1') } catch { /* ignore */ }
}

interface Props {
  pageId: string
  enabled?: boolean
  storage?: StorageAdapter
  onExport?: (payload: ExportPayload) => void
  children?: ReactNode
}

export function SpecBridgeAnnotation({
  pageId,
  enabled: initialEnabled = true,
  storage = localStorageAdapter,
  onExport,
  children,
}: Props) {
  const [enabled, setEnabled] = useState(initialEnabled)
  const [showGuide, setShowGuide] = useState(() => !hasDismissedForever())
  const [showLogoTip, setShowLogoTip] = useState(false)
  const [adding, setAdding] = useState(false)
  const [showList, setShowList] = useState(false)
  const [showResolved, setShowResolved] = useState(false)
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const [filterLabelIds, setFilterLabelIds] = useState<Set<string>>(new Set())
  /** null = 전체 보기, string = 특정 검토 회차 */
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null)
  const [hoveredId, setHoveredId] = useState<string | null>(null)
  const hoverTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  const [showAuthorModal, setShowAuthorModal] = useState(false)
  const [showLabelModal, setShowLabelModal] = useState(false)
  const [lastLabelId, setLastLabelIdState] = useState<string | null>(null)
  const [latestSdkVersion, setLatestSdkVersion] = useState<string | null>(null)
  const [, setResizeTick] = useState(0)

  // 뷰포트 리사이즈 / 스크롤 시 핀 위치 재계산용 강제 리렌더
  useEffect(() => {
    const onResize = () => setResizeTick((t) => t + 1)
    const onScroll = () => setResizeTick((t) => t + 1)
    window.addEventListener('resize', onResize)
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => {
      window.removeEventListener('resize', onResize)
      window.removeEventListener('scroll', onScroll)
    }
  }, [])

  // Pretendard 폰트 CDN 1회 주입
  useEffect(() => {
    const id = 'specbridge-pretendard'
    if (document.getElementById(id)) return
    const link = document.createElement('link')
    link.id = id
    link.rel = 'stylesheet'
    link.href = 'https://cdn.jsdelivr.net/gh/orioncactus/pretendard@v1.3.9/dist/web/variable/pretendardvariable-dynamic-subset.css'
    document.head.appendChild(link)
  }, [])

  // SDK 버전 체크 (httpAdapter 에서만 동작)
  useEffect(() => {
    if (!storage.checkSdkVersion) return
    storage.checkSdkVersion().then(({ latest }) => {
      if (latest) setLatestSdkVersion(latest)
    }).catch(() => {})
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // 저장된 마지막 레이블 비동기 로드
  useEffect(() => {
    let cancelled = false
    storage
      .loadLastLabelId()
      .then((v) => {
        if (!cancelled) setLastLabelIdState(v)
      })
      .catch((e) => console.error('[specbridge] loadLastLabelId failed', e))
    return () => {
      cancelled = true
    }
  }, [storage])

  // 마지막 선택 세션 복원
  useEffect(() => {
    storage.loadCurrentSessionId().then((id) => {
      if (id) setCurrentSessionId(id)
    }).catch(() => {})
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const { author, setAuthor, defaultLabelId, setDefaultLabelId } = useAuthor(storage)
  const { labels, addLabel, updateLabel, deleteLabel } = useLabels(storage)
  const { sessions, addSession, updateSession, setSessionStatus, setSessionViewport, deleteSession } = useSessions(storage)

  const handleSelectSession = useCallback((id: string | null) => {
    setCurrentSessionId(id)
    storage.saveCurrentSessionId(id).catch(() => {})
    setSelectedId(null)
  }, [storage])

  const handleCreateSession = useCallback(
    async (name: string, options?: { viewport?: SessionViewport | null }): Promise<string | null> => {
      const session = await addSession(name, options)
      if (!session) return null
      handleSelectSession(session.id)
      return session.id
    },
    [addSession, handleSelectSession]
  )

  const handleDeleteSession = useCallback(async (id: string) => {
    await deleteSession(id)
    if (currentSessionId === id) handleSelectSession(null)
  }, [deleteSession, currentSessionId, handleSelectSession])
  const {
    allAnnots,
    pins: allPagePins,
    addPin,
    updatePin,
    deletePin,
    movePin,
    addComment,
    updateComment,
    deleteComment,
    resolvePin,
    reopenPin,
  } = useAnnotations(pageId, storage)

  const labelById = useMemo(() => new Map(labels.map((l) => [l.id, l])), [labels])

  // 보여줄 핀 목록 (세션 필터 → resolved 필터 → 레이블 필터 — 선택된 핀은 항상 포함)
  const visiblePins = useMemo<Pin[]>(() => {
    let pins = allPagePins
    // 세션 필터: null = 전체, string = 해당 세션만
    if (currentSessionId !== null) {
      pins = pins.filter((p) => p.id === selectedId || p.sessionId === currentSessionId)
    }
    // resolved 필터
    if (!showResolved) {
      pins = pins.filter((p) => p.status !== 'resolved' || p.id === selectedId)
    }
    // 레이블 필터
    if (filterLabelIds.size > 0) {
      pins = pins.filter((p) => p.id === selectedId || (p.labelId != null && filterLabelIds.has(p.labelId)))
    }
    return pins
  }, [allPagePins, showResolved, selectedId, filterLabelIds, currentSessionId])

  const resolvedCountThisPage = useMemo(
    () => allPagePins.filter((p) => p.status === 'resolved').length,
    [allPagePins]
  )

  // 회차별 진행률 (전체 페이지 합산)
  const sessionProgress = useMemo(() => {
    const progress: Record<string, { total: number; resolved: number }> = {}
    for (const pins of Object.values(allAnnots)) {
      for (const pin of pins) {
        const sid = pin.sessionId ?? '__none__'
        if (!progress[sid]) progress[sid] = { total: 0, resolved: 0 }
        progress[sid].total++
        if (pin.status === 'resolved') progress[sid].resolved++
      }
    }
    return progress
  }, [allAnnots])

  // 레이블별 핀 사용량 (전체 페이지 합산)
  const pinUsage = useMemo(() => {
    const usage: Record<string, number> = {}
    for (const list of Object.values(allAnnots)) {
      for (const p of list) {
        if (p.labelId) usage[p.labelId] = (usage[p.labelId] ?? 0) + 1
      }
    }
    return usage
  }, [allAnnots])

  const rememberLastLabel = useCallback(
    (id: string | null) => {
      if (!id) return
      setLastLabelIdState(id)
      storage.saveLastLabelId(id)
    },
    [storage]
  )

  // defaultLabelId 가 없으면(신규 사용자) 첫 번째 레이블로 자동 초기화
  useEffect(() => {
    if (!defaultLabelId && labels.length > 0) {
      setDefaultLabelId(labels[0].id)
    }
  }, [labels, defaultLabelId, setDefaultLabelId])

  // 삭제된 레이블이 lastLabelId 였다면 초기화
  useEffect(() => {
    if (lastLabelId && !labels.some((l) => l.id === lastLabelId)) {
      setLastLabelIdState(null)
      storage.saveLastLabelId(null)
    }
  }, [labels, lastLabelId, storage])

  // pageId 바뀌면 선택/배치 상태 초기화
  useEffect(() => {
    setSelectedId(null)
    setAdding(false)
  }, [pageId])

  // enabled 꺼지면 세부 상태 리셋
  useEffect(() => {
    if (!enabled) {
      setAdding(false)
      setShowList(false)
      setSelectedId(null)
      setShowLabelModal(false)
    }
  }, [enabled])

  // 필터로 숨겨진 핀이 선택돼 있으면 자동 해제
  useEffect(() => {
    if (selectedId && !visiblePins.some((p) => p.id === selectedId)) {
      setSelectedId(null)
    }
  }, [selectedId, visiblePins])

  // ESC 로 배치 취소
  useEffect(() => {
    if (!adding) return
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setAdding(false)
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [adding])

  // A 키로 Annotation 모드 ON/OFF 토글
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.code !== 'KeyA') return
      if (e.ctrlKey || e.metaKey || e.altKey || e.shiftKey) return
      const t = e.target as HTMLElement | null
      if (t) {
        const tag = t.tagName
        if (tag === 'INPUT' || tag === 'TEXTAREA' || t.isContentEditable) return
      }
      e.preventDefault()
      setEnabled((v) => !v)
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [])

  // N 키로 번호 추가 토글
  useEffect(() => {
    if (!enabled) return
    const onKey = (e: KeyboardEvent) => {
      if (e.code !== 'KeyN') return
      if (e.ctrlKey || e.metaKey || e.altKey || e.shiftKey) return
      const t = e.target as HTMLElement | null
      if (t) {
        const tag = t.tagName
        if (tag === 'INPUT' || tag === 'TEXTAREA' || t.isContentEditable) return
      }
      e.preventDefault()
      if (!author) {
        setShowAuthorModal(true)
        return
      }
      setAdding((v) => !v)
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [enabled, author])

  // L 키로 목록 토글
  useEffect(() => {
    if (!enabled) return
    const onKey = (e: KeyboardEvent) => {
      if (e.code !== 'KeyL') return
      if (e.ctrlKey || e.metaKey || e.altKey || e.shiftKey) return
      const t = e.target as HTMLElement | null
      if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) return
      e.preventDefault()
      setShowList((v) => !v)
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [enabled])

  const handleLayerClick = useCallback(
    async (e: React.MouseEvent) => {
      if (!adding) return
      if (!author) {
        setShowAuthorModal(true)
        return
      }
      const layer = document.getElementById(CONTAINER_ID)
      if (!layer) return
      const rect = layer.getBoundingClientRect()
      // 우선순위: 작성자 기본 레이블 → 마지막 사용 레이블 → 첫 번째 레이블
      const defaultExists = defaultLabelId && labels.some((l) => l.id === defaultLabelId)
      const lastExists = lastLabelId && labels.some((l) => l.id === lastLabelId)
      const resolvedLabelId = defaultExists
        ? defaultLabelId
        : lastExists
        ? lastLabelId
        : (labels[0]?.id ?? null)
      // 꼭지점(좌하단)이 클릭 위치에 오도록: x offset=0, y offset=-28 (div 높이)
      // 화면 경계 클램핑: 핀(28px)이 항상 뷰포트 안에 보이도록
      const PIN_SIZE = 28
      const MARGIN = 4
      const rawX = e.clientX - rect.left
      const rawY = e.clientY - rect.top - PIN_SIZE
      const clampedX = Math.max(MARGIN, Math.min(rawX, rect.width - PIN_SIZE - MARGIN))
      const clampedY = Math.max(MARGIN, Math.min(rawY, rect.height - PIN_SIZE - MARGIN))
      // 뷰포트 비율(0~1)로 저장 — 브라우저 크기 변경에도 위치 유지
      const pin = await addPin(clampedX / rect.width, clampedY / rect.height, author, resolvedLabelId, currentSessionId)
      if (!pin) return
      // 기본 레이블이 없는 경우에만 lastLabel 갱신 (기본 레이블이 있으면 lastLabel은 변경 안 함)
      if (!defaultExists) rememberLastLabel(resolvedLabelId)
      setSelectedId(pin.id)
      setAdding(false)
    },
    [adding, author, addPin, labels, lastLabelId, defaultLabelId, rememberLastLabel]
  )

  // 패널 닫기 — 노트 없는 빈 핀은 자동 삭제
  const handlePanelClose = useCallback(() => {
    const pin = allPagePins.find((p) => p.id === selectedId)
    if (pin && !pin.note?.trim()) deletePin(pin.id)
    setSelectedId(null)
  }, [allPagePins, selectedId, deletePin])

  const handleUpdatePin = useCallback(
    async (id: string, patch: Partial<Omit<Pin, 'id' | 'comments'>>) => {
      await updatePin(id, patch)
      if (patch.labelId !== undefined) rememberLastLabel(patch.labelId)
    },
    [updatePin, rememberLastLabel]
  )

  const handleResolve = useCallback(
    (pinId: string) => {
      if (!author) {
        setShowAuthorModal(true)
        return
      }
      void resolvePin(pinId, author)
    },
    [author, resolvePin]
  )

  const handleExport = useCallback(() => {
    const payload: ExportPayload = {
      exportedAt: new Date().toISOString(),
      annotations: allAnnots,
      labels,
    }
    if (onExport) {
      onExport(payload)
      return
    }
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'annotations.json'
    a.click()
    URL.revokeObjectURL(url)
  }, [allAnnots, labels, onExport])

  // ── 핀 호버 — delay로 툴팁→핀 마우스 이동 시 깜빡임 방지 ──
  const handlePinHoverEnter = useCallback((id: string) => {
    if (hoverTimer.current) {
      clearTimeout(hoverTimer.current)
      hoverTimer.current = null
    }
    setHoveredId(id)
  }, [])

  const handlePinHoverLeave = useCallback((_id: string) => {
    hoverTimer.current = setTimeout(() => {
      setHoveredId(null)
      hoverTimer.current = null
    }, 60)
  }, [])

  // ── currentSessionId 가 삭제된 세션을 가리키면 null 로 초기화 ──
  useEffect(() => {
    if (currentSessionId !== null && sessions.length > 0 && !sessions.some((s) => s.id === currentSessionId)) {
      handleSelectSession(null)
    }
  }, [sessions, currentSessionId, handleSelectSession])

  // ── 세션이 1개뿐(최초 자동 생성)이면 자동 선택 ──
  useEffect(() => {
    if (sessions.length === 1 && currentSessionId === null) {
      handleSelectSession(sessions[0].id)
    }
  }, [sessions, currentSessionId, handleSelectSession])

  return (
    <div
      id={CONTAINER_ID}
      style={{
        position: 'relative',
        minHeight: '100%',
        overflow: 'hidden',  // 절대 위치 자식이 문서 스크롤 높이에 영향주지 않도록
      }}
    >
      {children}

      {/* ── 핀 레이어 + 클릭 캡처: position:absolute — 페이지 스크롤과 함께 이동 ── */}
      {enabled && (
        <div
          id={LAYER_ID}
          onClick={handleLayerClick}
          style={{
            position: 'absolute',
            inset: 0,
            zIndex: 9990,
            cursor: adding ? 'crosshair' : 'default',
            pointerEvents: adding ? 'all' : 'none',
          }}
        >
          {/* 핀은 pointerEvents: all 로 개별 처리 */}
          <div style={{ pointerEvents: 'none' }}>
            {visiblePins.map((pin) => {
              const label = pin.labelId ? labelById.get(pin.labelId) : undefined
              const isHov = pin.id === hoveredId
              const isSel = pin.id === selectedId
              return (
                <AnnotPin
                  key={pin.id}
                  pin={pin}
                  num={pin.num}
                  label={label}
                  layerId={CONTAINER_ID}
                  isSelected={isSel}
                  isHovered={isHov}
                  onSelect={() => setSelectedId(isSel ? null : pin.id)}
                  onMove={(pos) => movePin(pin.id, pos)}
                  onHoverEnter={handlePinHoverEnter}
                  onHoverLeave={handlePinHoverLeave}
                />
              )
            })}
          </div>
        </div>
      )}

      {enabled && showList && (
        <AnnotList
          pins={visiblePins}
          labels={labels}
          pageId={pageId}
          selectedId={selectedId}
          hoveredId={hoveredId}
          showResolved={showResolved}
          resolvedCount={resolvedCountThisPage}
          onSelect={(id) => setSelectedId(id)}
          onHover={(id) => setHoveredId(id ?? null)}
          onToggleShowResolved={() => setShowResolved((v) => !v)}
          onClose={() => setShowList(false)}
        />
      )}

      {enabled && selectedId && (() => {
        const selectedPin = allPagePins.find((p) => p.id === selectedId)
        if (!selectedPin) return null
        return (
          <>
            {/* 외부 클릭 시 패널 닫기 */}
            <div
              style={{ position: 'fixed', inset: 0, zIndex: 9989 }}
              onClick={handlePanelClose}
            />
            <AnnotPanel
              pins={allPagePins}
              selectedId={selectedId}
              anchor={(() => {
                const el = document.getElementById(CONTAINER_ID)
                const r = el?.getBoundingClientRect()
                return {
                  x: r ? r.left + selectedPin.x * r.width : selectedPin.x * window.innerWidth,
                  y: r ? r.top + selectedPin.y * r.height : selectedPin.y * window.innerHeight,
                }
              })()}
              labels={labels}
              currentAuthor={author}
              leftBound={showList ? 252 : 0}
              onClose={handlePanelClose}
              onUpdate={handleUpdatePin}
              onDelete={(id) => {
                deletePin(id)
                setSelectedId(null)
              }}
              onManageLabels={() => setShowLabelModal(true)}
              onAddComment={(pinId, text) => addComment(pinId, author, text)}
              onUpdateComment={updateComment}
              onDeleteComment={deleteComment}
              onResolve={handleResolve}
              onReopen={reopenPin}
            />
          </>
        )
      })()}

      {showAuthorModal && (
        <AuthorModal
          currentAuthor={author}
          currentDefaultLabelId={defaultLabelId}
          labels={labels}
          onSave={(name, labelId) => {
            setAuthor(name)
            setDefaultLabelId(labelId)
            setShowAuthorModal(false)
          }}
          onCancel={() => setShowAuthorModal(false)}
        />
      )}

      {showLabelModal && (
        <LabelManagerModal
          labels={labels}
          pinUsage={pinUsage}
          onAdd={addLabel}
          onUpdate={updateLabel}
          onDelete={deleteLabel}
          onClose={() => setShowLabelModal(false)}
        />
      )}

      {showGuide && (
        <OnboardingGuide
          onClose={(forever) => {
            setShowGuide(false)
            // "다시 보지 않음" 체크 없이 처음 닫는 경우 → 로고 툴팁 1회 노출
            if (!forever && !hasShownLogoTip()) {
              markLogoTipShown()
              setShowLogoTip(true)
              setTimeout(() => setShowLogoTip(false), 5000)
            }
          }}
        />
      )}

      <AnnotationToolbar
        enabled={enabled}
        onToggleEnabled={() => setEnabled((v) => !v)}
        author={author}
        onEditAuthor={() => setShowAuthorModal(true)}
        adding={adding}
        onToggleAdd={() => {
          if (!author) {
            setShowAuthorModal(true)
            return
          }
          setAdding((v) => !v)
        }}
        pinCount={visiblePins.length}
        showList={showList}
        onToggleList={() => {
          setShowList((v) => !v)
          setSelectedId(null)
        }}
        onExport={handleExport}
        labels={labels}
        filterLabelIds={filterLabelIds}
        onToggleLabelFilter={(id) =>
          setFilterLabelIds((prev) => {
            const next = new Set(prev)
            next.has(id) ? next.delete(id) : next.add(id)
            return next
          })
        }
        onClearLabelFilter={() => setFilterLabelIds(new Set())}
        latestSdkVersion={latestSdkVersion}
        onShowGuide={() => { setShowGuide(true); setShowLogoTip(false) }}
        showLogoTip={showLogoTip}
        sessions={sessions}
        currentSessionId={currentSessionId}
        sessionProgress={sessionProgress}
        onSelectSession={handleSelectSession}
        onCreateSession={handleCreateSession}
        onDeleteSession={handleDeleteSession}
        onUpdateSession={updateSession}
        onSetSessionStatus={setSessionStatus}
        onSetSessionViewport={setSessionViewport}
      />
    </div>
  )
}
