/**
 * 이 apiKey 가 속한 프로젝트 정보를 서버에서 조회.
 *
 *   const info = await whoami({ baseUrl, apiKey })
 *   console.log(info.name, info.slug)
 */
export interface WhoamiInfo {
  id: string
  name: string
  slug: string
  description: string | null
}

export async function whoami(options: {
  baseUrl: string
  apiKey: string
}): Promise<WhoamiInfo> {
  const url = `${options.baseUrl.replace(/\/+$/, '')}/api/whoami`
  const res = await fetch(url, {
    headers: {
      Accept: 'application/json',
      Authorization: `Bearer ${options.apiKey}`,
    },
  })
  if (!res.ok) {
    throw new Error(`whoami failed: ${res.status}`)
  }
  return (await res.json()) as WhoamiInfo
}
